"use client";

/**
 * 採用パイプライン管理画面（ATS / applicant tracking）
 * — @gunjo/ui@0.0.1-alpha.2 をコンテキストゼロから採用して構築。
 *
 * 架空のHR-tech企業「ミドリリンク株式会社」のインハウス採用デスク。
 * リクルーターが (1) ファネル全体を俯瞰し、(2) 今週の面接を確認し、
 * (3) 候補者にドリルインし、(4) 承認フローで次ステージへ進める、という一連の業務を再現。
 *
 * 使用した @gunjo/ui コンポーネント:
 *   レイアウト  : Container, VStack
 *   表示        : Statistic, KanbanBoard, Badge, Avatar/AvatarFallback, Rating,
 *                 DistributionBar, Separator, Timeline*, MetadataList
 *   入力        : Button, SearchInput, Select, ApprovalWorkflow
 *   カレンダー  : WeekView
 *   オーバーレイ: Sheet (候補者ドリルイン), Tooltip(Avatar内)
 *   フィードバック: Progress (ステージ通過率)
 */

import * as React from "react";
import {
  Avatar,
  AvatarFallback,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Container,
  DistributionBar,
  KanbanBoard,
  Rating,
  SearchInput,
  Select,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  Statistic,
  TooltipProvider,
  VStack,
  WeekView,
  formatPercent,
  type WeekEvent,
  type WorkflowValue,
} from "@gunjo/ui";

import {
  CANDIDATES,
  INTERVIEWS,
  STAGES,
  STAGE_LABEL,
  CHANNEL_LABEL,
  ROLE_LABEL,
  TODAY,
  WEEK_OF,
  APPROVAL_ROUTE,
  type Candidate,
  type StageId,
  type Channel,
} from "./data";
import { CandidateDetail } from "./CandidateDetail";

const RECRUITER = "山口 美和"; // ログイン中の採用責任者（承認操作者）

const channelTone: Record<Channel, "info" | "success" | "warning" | "secondary"> = {
  referral: "success",
  media: "info",
  agent: "warning",
  direct: "secondary",
};

function initials(name: string): string {
  // 姓の1文字目（日本語名想定）。
  return name.replace(/\s/g, "").slice(0, 1);
}

export default function RecruitingPipelinePage() {
  const [query, setQuery] = React.useState("");
  const [roleFilter, setRoleFilter] = React.useState<string>("all");
  const [selectedId, setSelectedId] = React.useState<string | null>(null);

  // 候補者ごとの内定承認フロー状態。初期値: 最終/内定段階の候補者は承認ルートを起票済み。
  const [approvals, setApprovals] = React.useState<Record<string, WorkflowValue>>(() => {
    const init: Record<string, WorkflowValue> = {};
    for (const c of CANDIDATES) {
      if (c.stage === "offer") {
        // 内定段階：現場確認済み、採用責任者承認まで進行中。
        init[c.id] = {
          currentStageId: "manager",
          status: "in-progress",
          records: {
            field: { actor: "現場面接官", at: "2026-06-22 18:30" },
          },
        };
      } else {
        init[c.id] = { currentStageId: APPROVAL_ROUTE[0].id, status: "in-progress", records: {} };
      }
    }
    return init;
  });

  const activeCandidates = CANDIDATES.filter((c) => c.outcome === "active");

  // 検索 + 職種フィルタ。
  const filtered = React.useMemo(() => {
    const q = query.trim();
    return CANDIDATES.filter((c) => {
      if (roleFilter !== "all" && c.role !== roleFilter) return false;
      if (!q) return true;
      return (
        c.name.includes(q) ||
        c.kana.includes(q) ||
        c.role.includes(q) ||
        c.recruiter.includes(q)
      );
    });
  }, [query, roleFilter]);

  // パイプライン上の候補者（見送りは別レーンにせず除外し、ファネルに集中）。
  const pipelineCandidates = filtered.filter((c) => c.outcome === "active");

  // サマリ指標。
  const total = CANDIDATES.length;
  const inProgress = activeCandidates.filter((c) => c.stage !== "offer").length;
  const offerCount = activeCandidates.filter((c) => c.stage === "offer").length;
  const thisWeekInterviews = INTERVIEWS.length;

  // ステージ通過率（応募受付を母数として、各ステージ以降に到達した割合）。
  const stageReach = STAGES.map((s, idx) => {
    const reachedIds = STAGES.slice(idx).map((x) => x.id) as StageId[];
    const count = CANDIDATES.filter(
      (c) => reachedIds.includes(c.stage) || (c.outcome === "active" && reachedIds.includes(c.stage))
    ).length;
    return { stage: s, count };
  });
  const appliedTotal = total;
  const screeningPassRate = stageReach[1].count / appliedTotal;
  const firstInterviewRate = stageReach[2].count / appliedTotal;

  // 応募経路の内訳（DistributionBar 用）。
  const channelDist = (Object.keys(CHANNEL_LABEL) as Channel[]).map((ch) => ({
    label: CHANNEL_LABEL[ch],
    value: CANDIDATES.filter((c) => c.channel === ch).length,
    color: channelTone[ch],
  }));

  // 今週の面接を WeekView イベントへ。
  const interviewEvents: WeekEvent[] = INTERVIEWS.map((iv) => ({
    id: iv.id,
    start: iv.start,
    end: iv.end,
    label: `${iv.candidateName}・${iv.round}`,
    tone: iv.format === "online" ? "info" : "primary",
    ariaLabel: `${iv.candidateName} ${iv.role} ${iv.round} ${
      iv.format === "online" ? "オンライン" : "対面"
    } 面接官 ${iv.interviewers.join("、")}`,
  }));

  const selected = selectedId ? CANDIDATES.find((c) => c.id === selectedId) ?? null : null;

  const openCandidate = (c: Candidate) => setSelectedId(c.id);
  const openInterview = (ev: WeekEvent) => {
    const iv = INTERVIEWS.find((i) => i.id === ev.id);
    if (iv) setSelectedId(iv.candidateId);
  };

  return (
    <TooltipProvider>
      <Container className="py-6">
        <VStack gap={6}>
          {/* ヘッダ */}
          <header className="flex flex-col gap-1">
            <p className="text-xs font-medium text-muted-foreground">ミドリリンク株式会社 / 人事・採用</p>
            <h1 className="text-2xl font-bold text-foreground">採用パイプライン</h1>
            <p className="text-sm text-muted-foreground">
              担当：{RECRUITER}（採用責任者）・2026年6月度 中途採用
            </p>
          </header>

          {/* サマリ指標 */}
          <section aria-label="サマリ指標">
            <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
              <Statistic label="応募総数" value={total} hint="2026年6月度" />
              <Statistic label="選考中" value={inProgress} tone="neutral" />
              <Statistic label="今週面接" value={thisWeekInterviews} hint="6/22〜6/28" />
              <Statistic
                label="内定（承認中含む）"
                value={offerCount}
                trend="up"
                change="+1"
                hint="前週比"
              />
              <Statistic
                label="書類選考 通過率"
                value={formatPercent(screeningPassRate, { maximumFractionDigits: 0 })}
                hint={`一次到達 ${formatPercent(firstInterviewRate, { maximumFractionDigits: 0 })}`}
              />
            </div>
          </section>

          {/* メイン: パイプライン + 右ペイン(今週の面接 + 経路内訳) */}
          <div className="grid gap-4 lg:grid-cols-[minmax(0,1fr)_320px]">
            {/* 選考パイプライン (Kanban) */}
            <Card className="min-w-0">
              <CardHeader className="flex flex-col gap-3">
                <div className="flex flex-wrap items-center justify-between gap-2">
                  <CardTitle>選考パイプライン</CardTitle>
                  <Badge variant="outline">{pipelineCandidates.length} 名</Badge>
                </div>
                <div className="flex flex-col gap-2 sm:flex-row">
                  <SearchInput
                    value={query}
                    onValueChange={setQuery}
                    placeholder="氏名・ふりがな・職種で検索"
                    aria-label="候補者を検索"
                    className="sm:max-w-xs"
                  />
                  <Select
                    aria-label="職種で絞り込み"
                    value={roleFilter}
                    onChange={(e) => setRoleFilter(e.target.value)}
                    className="sm:max-w-[200px]"
                  >
                    <option value="all">すべての職種</option>
                    {Object.values(ROLE_LABEL).map((r) => (
                      <option key={r} value={r}>
                        {r}
                      </option>
                    ))}
                  </Select>
                </div>
              </CardHeader>
              <CardContent>
                <KanbanBoard
                  columns={STAGES.map((s) => ({
                    id: s.id,
                    title: STAGE_LABEL[s.id],
                    tone: s.tone as never,
                  }))}
                  items={pipelineCandidates}
                  getItemId={(c) => c.id}
                  getColumnId={(c) => c.stage}
                  onCardSelect={openCandidate}
                  columnWidth={220}
                  emptyLabel="該当なし"
                  renderCard={(c) => (
                    <div className="flex flex-col gap-1.5">
                      <div className="flex items-center gap-2">
                        <Avatar
                          className="h-7 w-7 text-xs"
                          tooltip={`担当: ${c.recruiter}`}
                        >
                          <AvatarFallback className="text-xs">{initials(c.name)}</AvatarFallback>
                        </Avatar>
                        <div className="min-w-0">
                          <p className="truncate text-sm font-semibold text-foreground">{c.name}</p>
                          <p className="truncate text-[11px] text-muted-foreground">{c.role}</p>
                        </div>
                      </div>
                      <div className="flex flex-wrap items-center gap-1">
                        <Badge variant={channelTone[c.channel]} className="text-[10px]">
                          {CHANNEL_LABEL[c.channel]}
                        </Badge>
                        {c.rating > 0 ? (
                          <Rating value={c.rating} size="sm" label={`評価 ${c.rating} / 5`} />
                        ) : null}
                      </div>
                    </div>
                  )}
                />
              </CardContent>
            </Card>

            {/* 右ペイン */}
            <VStack gap={4} className="min-w-0">
              {/* 応募経路の内訳 */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">応募経路の内訳</CardTitle>
                </CardHeader>
                <CardContent>
                  <DistributionBar
                    segments={channelDist}
                    aria-label="応募経路の内訳"
                    showLegend
                  />
                </CardContent>
              </Card>

              {/* ステージ別 在籍数 */}
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">ステージ別 在籍</CardTitle>
                </CardHeader>
                <CardContent className="flex flex-col gap-2">
                  {STAGES.map((s) => {
                    const n = activeCandidates.filter((c) => c.stage === s.id).length;
                    return (
                      <div key={s.id} className="flex items-center justify-between text-sm">
                        <span className="text-muted-foreground">{STAGE_LABEL[s.id]}</span>
                        <span className="font-semibold tabular-nums text-foreground">{n}</span>
                      </div>
                    );
                  })}
                </CardContent>
              </Card>
            </VStack>
          </div>

          {/* 今週の面接 (WeekView) */}
          <Card>
            <CardHeader className="flex flex-row flex-wrap items-center justify-between gap-2">
              <CardTitle>今週の面接日程</CardTitle>
              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                <span className="inline-flex items-center gap-1">
                  <span className="inline-block h-2.5 w-2.5 rounded-full border border-info-border bg-info-subtle" />
                  オンライン
                </span>
                <span className="inline-flex items-center gap-1">
                  <span className="inline-block h-2.5 w-2.5 rounded-full border border-primary/40 bg-primary/15" />
                  対面
                </span>
              </div>
            </CardHeader>
            <CardContent>
              <WeekView
                weekOf={WEEK_OF}
                today={TODAY}
                events={interviewEvents}
                startHour={9}
                endHour={19}
                weekStartsOn={1}
                label="今週の面接日程"
                onSelectEvent={openInterview}
              />
            </CardContent>
          </Card>
        </VStack>
      </Container>

      {/* 候補者ドリルイン (Sheet) */}
      <Sheet open={selected !== null} onOpenChange={(open) => !open && setSelectedId(null)}>
        <SheetContent
          side="right"
          className="w-full overflow-y-auto sm:max-w-md md:max-w-lg"
          closeLabel="閉じる"
        >
          {selected ? (
            <>
              <SheetHeader>
                <SheetTitle>候補者カルテ</SheetTitle>
                <SheetDescription>
                  {ROLE_LABEL[selected.role]}・{CHANNEL_LABEL[selected.channel]}経由
                </SheetDescription>
              </SheetHeader>
              <div className="mt-4">
                <CandidateDetail
                  candidate={selected}
                  approval={approvals[selected.id]}
                  actor={RECRUITER}
                  onApprovalChange={(next) =>
                    setApprovals((prev) => ({ ...prev, [selected.id]: next }))
                  }
                />
              </div>
            </>
          ) : null}
        </SheetContent>
      </Sheet>
    </TooltipProvider>
  );
}

"use client";

import * as React from "react";
import {
  ApprovalWorkflow,
  Badge,
  Button,
  MetadataList,
  Rating,
  Separator,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineTime,
  TimelineDescription,
  type WorkflowValue,
} from "@gunjo/ui";

import {
  type Candidate,
  CHANNEL_LABEL,
  STAGE_LABEL,
  APPROVAL_ROUTE,
} from "./data";

const recoTone: Record<string, "success" | "warning" | "secondary"> = {
  推奨: "success",
  中立: "secondary",
  見送り: "warning",
};

export interface CandidateDetailProps {
  candidate: Candidate;
  /** 内定承認フローの状態（候補者ごと）。 */
  approval: WorkflowValue;
  onApprovalChange: (next: WorkflowValue) => void;
  /** 採用責任者の操作者名（承認記録に残る）。 */
  actor: string;
}

/**
 * 候補者ドリルイン：職務経歴サマリ / 各面接の評価コメント / 選考履歴 /
 * 次アクション ＋ 内定承認フロー（現場 → 採用責任者 → 内定承認）。
 */
export function CandidateDetail({
  candidate,
  approval,
  onApprovalChange,
  actor,
}: CandidateDetailProps) {
  const c = candidate;
  const reachedFinal = c.stage === "final" || c.stage === "offer";

  const meta = [
    { label: "応募職種", value: c.role },
    { label: "応募経路", value: CHANNEL_LABEL[c.channel] },
    { label: "応募日", value: c.appliedOn },
    {
      label: "現在ステージ",
      value:
        c.outcome === "rejected" ? (
          <Badge variant="destructive">見送り</Badge>
        ) : (
          STAGE_LABEL[c.stage]
        ),
    },
    { label: "経験年数", value: `${c.experienceYears} 年` },
    { label: "担当リクルーター", value: c.recruiter },
  ];

  return (
    <div className="flex flex-col gap-4">
      <div className="flex flex-col gap-1">
        <div className="flex flex-wrap items-center gap-2">
          <h2 className="text-xl font-bold text-foreground">{c.name}</h2>
          <span className="text-sm text-muted-foreground">{c.kana}</span>
          {c.rating > 0 ? (
            <Rating value={c.rating} showValue size="sm" label={`総合評価 ${c.rating} / 5`} />
          ) : (
            <span className="text-xs text-muted-foreground">評価未登録</span>
          )}
        </div>
        <p className="text-sm text-muted-foreground">{c.currentTitle}</p>
      </div>

      <Tabs defaultValue="profile" className="w-full">
        <TabsList className="w-full">
          <TabsTrigger value="profile" className="flex-1">
            概要
          </TabsTrigger>
          <TabsTrigger value="evals" className="flex-1">
            面接評価
          </TabsTrigger>
          <TabsTrigger value="history" className="flex-1">
            選考履歴
          </TabsTrigger>
          <TabsTrigger value="approval" className="flex-1">
            内定承認
          </TabsTrigger>
        </TabsList>

        {/* 概要：職務経歴サマリ + 属性 + 次アクション */}
        <TabsContent value="profile" className="flex flex-col gap-4 pt-2">
          <MetadataList items={meta} />
          <div>
            <h3 className="mb-1 text-sm font-semibold text-foreground">職務経歴サマリ</h3>
            <p className="text-sm leading-relaxed text-muted-foreground">{c.summary}</p>
          </div>
          <Separator />
          <div>
            <h3 className="mb-1 text-sm font-semibold text-foreground">次アクション</h3>
            <p className="rounded-md border border-info-border bg-info-subtle px-3 py-2 text-sm text-info-subtle-foreground">
              {c.nextAction}
            </p>
          </div>
        </TabsContent>

        {/* 面接評価：各面接の評価コメント */}
        <TabsContent value="evals" className="flex flex-col gap-3 pt-2">
          {c.evaluations.length === 0 ? (
            <p className="py-6 text-center text-sm text-muted-foreground">
              まだ面接評価は登録されていません。
            </p>
          ) : (
            c.evaluations.map((e, i) => (
              <div key={i} className="rounded-lg border border-border bg-card p-3">
                <div className="flex flex-wrap items-center justify-between gap-2">
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-semibold text-foreground">{e.round}</span>
                    <Badge variant={recoTone[e.recommendation]}>{e.recommendation}</Badge>
                  </div>
                  <Rating value={e.rating} showValue size="sm" label={`評価 ${e.rating} / 5`} />
                </div>
                <p className="mt-1 text-xs text-muted-foreground">
                  {e.interviewer}・{e.date}
                </p>
                <p className="mt-2 text-sm leading-relaxed text-foreground">{e.comment}</p>
              </div>
            ))
          )}
        </TabsContent>

        {/* 選考履歴：ステージ遷移ログ */}
        <TabsContent value="history" className="pt-2">
          <Timeline>
            {c.log.map((entry, i) => (
              <TimelineItem
                key={i}
                variant={entry.stage === "rejected" ? "destructive" : "active"}
                connector={i < c.log.length - 1}
              >
                <TimelineTitle>{STAGE_LABEL[entry.stage]}</TimelineTitle>
                <TimelineTime>{entry.date}</TimelineTime>
                <TimelineDescription>{entry.note}</TimelineDescription>
              </TimelineItem>
            ))}
          </Timeline>
        </TabsContent>

        {/* 内定承認：現場面接官 → 採用責任者 → 内定承認 */}
        <TabsContent value="approval" className="flex flex-col gap-3 pt-2">
          {reachedFinal ? (
            <>
              <p className="text-sm text-muted-foreground">
                最終面接を通過した候補者の内定承認ルートです。各段の承認者が確認し、差戻し・却下も記録されます。
              </p>
              <ApprovalWorkflow
                stages={APPROVAL_ROUTE}
                value={approval}
                onChange={onApprovalChange}
                actor={actor}
                advanceHint="承認前に評価コメントを確認してください"
                labels={{
                  advance: "次の承認へ",
                  finish: "内定を承認",
                  completed: "内定承認 完了",
                  rejected: "内定見送り（却下）",
                  reason: "コメント / 理由",
                  reasonPlaceholder: "差戻し・却下の理由を入力…",
                  sendBackTarget: "戻し先の承認段",
                }}
              />
            </>
          ) : (
            <p className="rounded-md border border-border bg-muted/30 px-3 py-6 text-center text-sm text-muted-foreground">
              内定承認ルートは <strong className="text-foreground">最終面接</strong> 通過後に有効になります。
              <br />
              現在のステージ：{STAGE_LABEL[c.stage]}
            </p>
          )}
        </TabsContent>
      </Tabs>

      <Separator />
      <Button asChild variant="link" className="self-start px-0">
        <a href={`mailto:recruiting@midori-link.example.jp?subject=${encodeURIComponent(c.name)}様の選考について`}>
          候補者にメールを送る
        </a>
      </Button>
    </div>
  );
}

/**
 * 採用パイプライン（ATS）のサンプルデータ。
 * 架空のHR-tech企業「ミドリリンク株式会社」の中途採用を想定した、
 * 現実味のある候補者・職種・面接日程・評価データ。
 *
 * 注: 日付は 2026 年 6 月の「今週」（6/22 月 〜 6/28 日）を基準に組んでいる。
 */

export type StageId =
  | "applied" // 応募受付
  | "screening" // 書類選考
  | "interview1" // 一次面接
  | "interview2" // 二次面接
  | "final" // 最終面接
  | "offer"; // 内定

export type Outcome = "active" | "rejected";

export type Channel = "referral" | "media" | "agent" | "direct";

export type Role =
  | "バックエンドエンジニア"
  | "フロントエンドエンジニア"
  | "プロダクトデザイナー"
  | "カスタマーサクセス"
  | "経理";

export type Format = "online" | "onsite";

/** 採用責任者による承認ルートの段（現場 → 採用責任者 → 内定承認）。 */
export interface ApprovalStageDef {
  id: string;
  label: string;
}

export interface StageLogEntry {
  stage: StageId | "rejected";
  /** ステージに到達/遷移した日付（YYYY-MM-DD）。 */
  date: string;
  /** だれが/どんな判断で動かしたか。 */
  note: string;
}

export interface InterviewEval {
  /** どの面接か（一次/二次/最終）。 */
  round: string;
  interviewer: string;
  /** 5段階評価。 */
  rating: number;
  /** 合否傾向。 */
  recommendation: "推奨" | "中立" | "見送り";
  comment: string;
  date: string;
}

export interface Interview {
  id: string;
  candidateId: string;
  candidateName: string;
  role: Role;
  round: string;
  /** "YYYY-MM-DDTHH:mm" */
  start: string;
  end: string;
  interviewers: string[];
  format: Format;
}

export interface Candidate {
